proof:
by
      obtain ⟨ N, hN, hN' ⟩ := H;
      refine' lt_of_le_of_ne ( refinement_le B hB hB' hB'' ) _;
      intro h_eq;
      obtain ⟨x, hx⟩ : ∃ x ∈ B N hN, x ≠ N := by
        contrapose! hN';
        refine' Set.eq_singleton_iff_nonempty_unique_mem.mpr ⟨ _, hN' ⟩;
        by_cases h_empty : B N hN = ∅;
        · specialize hB N hN ; simp_all +singlePass;
          exact D.not_bot_mem ( hB ▸ hN );
        · exact Set.nonempty_iff_ne_empty.mpr h_empty;
      have hx_le_N : x ≤ N := by
        exact hB N hN ▸ le_sSup hx.1;
      have hx_disjoint : Disjoint x (sSup (D \ {x})) := by
        apply D.sSupIndep;
        exact h_eq ▸ Set.mem_iUnion₂.mpr ⟨ N, hN, hx.1 ⟩;
      have hx_le_sSup : N ≤ sSup (D \ {x}) := by
        exact le_sSup ( by simpa [ hx.2.symm ] using hN );
      grind

